const techIconCategories = {
  React: 'JavaScript Library',
  'Next.js': 'Full-Stack React Framework',
  Vue: 'JavaScript Framework',
  'Tailwind CSS': 'CSS Framework',
  Bootstrap: 'CSS Framework',
  PHP: 'Server-Side Programming',
  Laravel: 'PHP Framework',
  MySQL: 'RDBMS',
  PostgreSQL: 'RDBMS',
  Supabase: 'BaaS',
  Firebase: 'BaaS',
  Git: 'Version Control',
  GitHub: 'Repository/Hosting',
  Figma: 'Design & Prototyping',
  'Adobe XD': 'Design & Prototyping',
  Canva: 'Design',
};

const excludedTechIcons = new Set([
  'HTML5',
  'CSS',
  'JavaScript',
  'Bootstrap',
  'Adobe XD',
  'Canva',
]);

const techIcons = techStackData
  .flatMap((section) =>
    section.icons.map((icon) => ({
      ...icon,
      category: techIconCategories[icon.name] ?? section.section,
    }))
  )
  .filter((icon) => !excludedTechIcons.has(icon.name));

export { techIcons }